import{_ as i,o as l,c as e,a2 as r}from"./chunks/framework.DIMps2S2.js";const b=JSON.parse('{"title":"助力活动","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/activities/boost.md","filePath":"zh-CN/rewards/activities/boost.md"}'),t={name:"rewards/activities/boost.md"};function o(n,a,s,d,h,c){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="助力活动" tabindex="-1">助力活动 <a class="header-anchor" href="#助力活动" aria-label="Permalink to &quot;助力活动&quot;">​</a></h1><p>助力活动（Boost Activity）是 LongBridge 平台推出的社交裂变型活动。用户通过邀请好友点击专属助力链接，为自己「助力（Boost）」，从而加速任务进度或提高奖励金额。</p><h2 id="参与条件" tabindex="-1">参与条件 <a class="header-anchor" href="#参与条件" aria-label="Permalink to &quot;参与条件&quot;">​</a></h2><ul><li>持有有效的 LongBridge 账户，账户状态正常</li><li>已完成实名认证（KYC）</li><li>账户所属地区/持牌人在活动覆盖范围内</li><li>部分活动要求有一定的交易历史或账户资产</li></ul><h2 id="任务类型" tabindex="-1">任务类型 <a class="header-anchor" href="#任务类型" aria-label="Permalink to &quot;任务类型&quot;">​</a></h2><ul><li>助力加速：好友为您助力后，您的任务进度增加或倒计时缩短</li><li>助力加码：好友助力后您的奖励金额按次提升</li><li>互助任务：您助力好友，好友助力您，双方各获收益</li></ul><h2 id="参与步骤" tabindex="-1">参与步骤 <a class="header-anchor" href="#参与步骤" aria-label="Permalink to &quot;参与步骤&quot;">​</a></h2><ol><li>在「活动中心」找到当期助力活动</li><li>点击「发起助力」生成专属助力链接</li><li>分享链接给好友，邀请好友点击助力</li><li>每位好友助力后，您的进度/奖励相应增加</li><li>助力次数达到上限或任务完成后，奖励触发发放</li><li>在「活动中心 → 我的奖励」查看奖励状态</li></ol><h2 id="奖励类型" tabindex="-1">奖励类型 <a class="header-anchor" href="#奖励类型" aria-label="Permalink to &quot;奖励类型&quot;">​</a></h2><ul><li>翻倍奖励：通过助力可将基础奖励翻倍</li><li>额外加成奖励：助力后在基础奖励上累加的额外金额</li><li>交易券/现金券：手续费抵扣或消费优惠</li></ul><h2 id="助力次数限制" tabindex="-1">助力次数限制 <a class="header-anchor" href="#助力次数限制" aria-label="Permalink to &quot;助力次数限制&quot;">​</a></h2><p>每个助力活动设有每人可接受助力次数上限（如每人最多接受 20 次助力）。达到上限后，新的助力请求不再生效。同一位好友在整个活动中只能助力一定次数。助力次数上限以活动详情页说明为准。</p><h2 id="奖励状态说明" tabindex="-1">奖励状态说明 <a class="header-anchor" href="#奖励状态说明" aria-label="Permalink to &quot;奖励状态说明&quot;">​</a></h2><ul><li>待发放（Pending）：任务已完成，奖励等待处理</li><li>发放中（Sending）：系统正在将奖励发送至账户，通常数小时内完成</li><li>已发放（Sent）：奖励已成功到账</li><li>锁定中（Lockup）：奖励已到账但处于锁定期</li><li>已解锁可用（Used）：锁定期结束，可正常使用</li><li>发放失败（Failed）：奖励发放失败，联系客服处理</li><li>已取消（Cancel）：奖励因规则原因取消，联系客服确认</li></ul><h2 id="助力规则与奖励发放答疑" tabindex="-1">助力规则与奖励发放答疑 <a class="header-anchor" href="#助力规则与奖励发放答疑" aria-label="Permalink to &quot;助力规则与奖励发放答疑&quot;">​</a></h2><p><strong>Q：助力次数有上限吗？我分享了很多次，有些助力没有生效？</strong><br> A：助力活动通常设有每人可接受的助力次数上限（以活动详情页为准）。达到上限后，新的助力将不再为您增加进度，即使好友点击了您的助力链接也不会生效。此外，同一位好友通常只能为您助力 1 次，重复点击不计入。建议分享给不同的新朋友。</p><p><strong>Q：我在活动中帮好友助力了，我有奖励吗？</strong><br> A：助力活动通常有两种奖励设计：（1）被助力者获得进度加速或奖励提升；（2）助力者也获得一定奖励（如小额现金或券）。是否有助力者奖励以具体活动规则为准，请查看活动详情页中「助力奖励」部分。</p><p><strong>Q：助力好友时，好友有哪些条件要求才能算有效助力？</strong><br> A：助力是否有效取决于活动设定的助力条件，常见要求包括：（1）好友需为 LongBridge 注册用户（已有账户或新注册均可）；（2）好友需在助力有效期内完成点击；（3）部分活动要求好友是新用户（未在平台注册过）。具体助力条件以活动详情页说明为准。</p><h2 id="助力资格与违规判定" tabindex="-1">助力资格与违规判定 <a class="header-anchor" href="#助力资格与违规判定" aria-label="Permalink to &quot;助力资格与违规判定&quot;">​</a></h2><ul><li>助力有次数上限，同一好友只能助力 1 次</li><li>助力链接有有效期，过期后分享的链接不再生效</li><li>账户 KYC 未完成无法领取助力奖励</li><li>奖励查看路径：APP「活动中心 → 我的奖励」</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards">活动与奖励</a></li></ul>',22)])])}const p=i(t,[["render",o]]);export{b as __pageData,p as default};
